  ('social-worker-moex-00675', 'social-worker', 'social-worker-moex-112-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '一位稱職的社工管理者所應具備的態度或行動，下列敘述何者錯誤？', '["創造員工參與決策的機會", "員工的利益凌駕於組織的利益", "尊重並接納員工的優點與限制", "強化員工對組織的歸屬感"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "1eb12fa153fb", "answer_pdf_sha1": "d6f9f114e1bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00676', 'social-worker', 'social-worker-moex-112-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在社會服務領域中，有關理性規劃的步驟，下列敘述何者錯誤？', '["經由主管進行組織目標的設定", "規劃者須衡量組織可運用資源的多寡", "經由腦力激盪列出與評量可供選擇的方案", "選擇、規劃與修正行動方案"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "1eb12fa153fb", "answer_pdf_sha1": "d6f9f114e1bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00677', 'social-worker', 'social-worker-moex-112-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '組織環境是環繞在組織周圍，能夠左右組織運作的潛在影響力。下列有關組織環境的敘述何者 錯誤？', '["包含組織內部環境與外部環境", "組織的文化屬內部環境的一部分", "外部環境可區分為任務環境和一般環境", "經濟、科技、政治、人口等，屬於組織的任務環境"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "1eb12fa153fb", "answer_pdf_sha1": "d6f9f114e1bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00678', 'social-worker', 'social-worker-moex-112-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關PaulHersey與KenBlanchard的情境領導理論的敘述，下列何者錯誤？', '["有效的領導型態須視部屬對自己行為負責的能力與意願而定", "部屬有能力且有意願對個人行為負責，應採授權式的領導風格", "部屬無能力但有意願對個人行為負責，應採參與式的領導風格", "部屬無能力且無意願對個人行為負責，應採告知式的領導風格"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "1eb12fa153fb", "answer_pdf_sha1": "d6f9f114e1bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00679', 'social-worker', 'social-worker-moex-112-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '當領導者的權力是來自於「職權」時，請問其權力來源為何？', '["法定的權力（legitimatepower）", "獎賞的權力（rewardpower）", "專家的權力（expertpower）", "參考的權力（referentpower）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "1eb12fa153fb", "answer_pdf_sha1": "d6f9f114e1bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00680', 'social-worker', 'social-worker-moex-112-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', 'Blake與Mouton的管理格局理論，認為領導者依其員工導向與生產導向程度的高低，會產生幾種 不同的領導型態，有關領導型態的敘述，下列何者錯誤？', '["工作效率與士氣，均保持適當中等水準與均衡，屬「中庸之道型（middleroad）」", "不強調生產，亦不重視員工需求，屬「不良管理型（impoverished）」", "生產效率與員工需求滿足俱佳，屬「團隊管理型（team）」", "只強調生產效率，不重視員工需求的滿足，屬「鄉村俱樂部型（country-club）」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "1eb12fa153fb", "answer_pdf_sha1": "d6f9f114e1bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
